-- Migration 012: Deprecate DASHBOARD_PASSWORD env var
--
-- No schema changes. This migration records that the DASHBOARD_PASSWORD
-- environment variable is no longer used for login authentication.
--
-- Action required for Coolify deployments:
--   1. Log in with your email+password at https://memory.fl1.it/
--   2. Remove the DASHBOARD_PASSWORD env var from Coolify environment settings
--   3. ADMIN_EMAIL remains required for email-based user management (invites)
--
-- The server still reads DASHBOARD_PASSWORD for first-run bootstrap (creates
-- an admin user if the users table is empty), then warns in logs to remove it.
SELECT 1;
